from flask import Flask, request, Response

app = Flask(__name__)

@app.route('/')
def route():
    content_type = request.args.get('content_type')
    if content_type:
        if content_type == 'text/plain':
            return Response('Hello, World!', mimetype='text/plain')
        elif content_type == 'text/html':
            return Response('<h1>Hello, World!</h1>', mimetype='text/html')
        elif content_type == 'application/json':
            return Response('{"message": "Hello, World!"}', mimetype='application/json')
        else:
            return Response('Unsupported content type', status=406)
    else:
        return Response('Content type is required', status=400)

if __name__ == '__main__':
    app.run(debug=True)
