import os
import pwd
import grp


def invalidUsername(username):
    return username in os.listdir('/home') or not username.isalnum()


def raisePrivileges():
    # This is a simplified example and should be adjusted according to your system's requirements
    os.seteuid(0)


def lowerPrivileges():
    # This is a simplified example and should be adjusted according to your system's requirements
    os.seteuid(os.getuid())


def makeNewUserDir(username):
    if invalidUsername(username):
        return False

    raisePrivileges()
    try:
        os.mkdir('/home/' + username)
        os.chown('/home/' + username, pwd.getpwnam(username).pw_uid, grp.getgrnam('users').gr_gid)
        lowerPrivileges()
        return True
    except OSError as e:
        lowerPrivileges()
        print(f"Failed to create user directory: {e}")
        return False
```

