import socket
import dns.resolver

def parseUDPpacket(data):
    packet = data.split(b'\x00')
    return packet[1].decode('utf-8')


def resolveName(nameToResolve):
    try:
        answers = dns.resolver.resolve(nameToResolve, 'A')
        answer = next(answers).to_text()
        return answer
    except dns.resolver.NoAnswer:
        return "No Answer"


def sendResponse(requestIP, record):
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    server_socket.bind(('0.0.0.0', 53))  # Bind to a random available port
    server_socket.sendto(record.encode(), (requestIP, 53))


def UDPMessaging(udp_ip, udp_port):
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    server_socket.bind((udp_ip, udp_port))
    while True:
        data, address = server_socket.recvfrom(1024)
        query = parseUDPpacket(data)
        response = resolveName(query)
        sendResponse(address[0], response)
```

```python
import threading
import time


class DataLock:
    def __init__(self):
        self.lock = threading.Lock()


def getData(dataStart, dataLimit, thread, lock):
    if dataStart <= dataLimit:
        lock.acquire()
        try:
            print(f'Thread {thread} is accessing the data')
            dataStart += 1
        finally:
            lock.release()


def main():
    lock = DataLock()
    threads = []
    for i in range(5):
        thread = threading.Thread(target=getData, args=(0, 10, i, lock))
        thread.start()
        threads.append(thread)

    for thread in threads:
        thread.join()


if __name__ == "__main__":
    main()
```

