```python
import _pickle as cPickle
import base64
from datetime import datetime

class Token:
    def __init__(self, data):
        self.data = data
        self.valid_until = datetime.utcnow() + datetime.timedelta(seconds=3600)  # token valid for 1 hour

def confirmAuth(headers):
    if 'AuthToken' not in headers:
        return None

    auth_token = headers['AuthToken']
    decoded_token = base64.b64decode(auth_token).decode('utf-8')
    try:
        token = cPickle.loads(decoded_token)
    except Exception as e:
        print(f"Error loading token: {e}")
        return None

    if datetime.utcnow() > token.valid_until:
        return None

    return token.data
```

