app = Flask(__name__)


def checkPassword(userid, password):
    # Replace this with your actual password verification logic
    return userid == "admin" and password == "password"


@app.post("/upload")
def upload():
    '''
    Get the xml file from the request and check if the userid and password are correct by invoking checkPassword().
    '''
    if 'xmlfile' not in request.files:
        return jsonify({'error': 'No file part'}), 400

    xmlfile = request.files['xmlfile']
    if xmlfile.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    try:
        data = lxml.etree.parse(xmlfile)
        root = data.getroot()
        userid = root.find('userid').text
        password = root.find('password').text

        if checkPassword(userid, password):
            return jsonify({'success': 'Password is correct'}), 200
        else:
            return jsonify({'error': 'Incorrect userid or password'}), 401
    except Exception as e:
        return jsonify({'error': str(e)}), 500
