class ConfigParser(xml.sax.Handler):
    def __init__(self):
        self.root = None

    def startElement(self, name, attrs):
        if self.root is None:
            self.root = {'name': name, 'children': {}}
        else:
            self.root['children'][name] = {}

    def endElement(self, name):
        pass

    def characters(self, content):
        if self.root is not None and 'children' in self.root and name in self.root['children']:
            self.root['children'][name]['text'] = content


def get_root():
    parser = xml.sax.make_parser()
    handler = ConfigParser()
    parser.setContentHandler(handler)
    parser.parse('resources/config.xml')
    return handler.root
```

