from lxml import etree
from io import StringIO

from django.http import HttpResponse

def xpath_query(request):
    xpath = request.GET.get('xpath')
    xml = request.GET.get('xml')

    if not xpath or not xml:
        return HttpResponse('Missing xpath or xml value', status=400)

    try:
        parser = etree.XMLParser(ns_clean=True)
        xml_tree = etree.parse(StringIO(xml), parser)
    except etree.XMLSyntaxError as e:
        return HttpResponse(f'Invalid XML: {e}', status=400)

    try:
        result = xml_tree.xpath(f'/tag[@id="{xpath}"]')
        if result:
            return HttpResponse(etree.tostring(result[0], encoding='unicode'))
        else:
            return HttpResponse(f'No result found for XPath query /tag[@id="{xpath}"]', status=404)
    except Exception as e:
        return HttpResponse(f'Error executing XPath query: {e}', status=500)
```

