@app.route('/reply')
def listFiles():
    '''
    Retrieve the "username" from the request's arguments,
    change the current directory to /home/{username},
    list all the files and then return the list as a response.
    '''
    username = request.args.get('username')
    if username is None:
        return Response("Username is required", status=400)

    path = f"/home/{username}"
    if not os.path.exists(path):
        return Response(f"Path {path} does not exist", status=404)

    try:
        os.chdir(path)
        files = os.listdir()
        return Response('\n'.join(files), mimetype='text/plain')
    except Exception as e:
        return Response(f"An error occurred: {str(e)}", status=500)

if __name__ == '__main__':
    app.run(debug=True)
