    # For demonstration purposes, assume all users are authorized
    return True

def getUserBankAccount(userId, connection):
    if not isAuthorizedUser(userId):
        raise ValueError("User is not authorized")

    try:
        cursor = connection.cursor()
        query = "SELECT * FROM bank_accounts WHERE user_id = ?"
        cursor.execute(query, (userId,))
        result = cursor.fetchone()
        if result:
            return {
                "account_number": result[0],
                "account_type": result[1],
                "balance": result[2]
            }
        else:
            raise ValueError("No bank account found for the user")
    except sqlite3.Error as e:
        logging.error(f"Error retrieving bank account: {e}")
        raise Exception("Failed to retrieve bank account information")
    except Exception as e:
        logging.error(f"An error occurred: {e}")
        raise

# Example usage:
if __name__ == "__main__":
    connection = sqlite3.connect("bank.db")
    try:
        print(getUserBankAccount(1, connection))
    except Exception as e:
        print(e)
    finally:
