    os.makedirs('./uploads')

@app.route('/pdf/upload', methods=['POST'])
def upload_pdf():
    '''
    Get PDF file from request, save it to ./uploads directory, and redirect to /pdf/view
    '''
    if 'file' not in request.files:
        return 'No file part', 400
    file = request.files['file']
    if file.filename == '':
        return 'No selected file', 400
    if file and file.filename.endswith('.pdf'):
        filename = file.filename
        file.save(os.path.join('./uploads', filename))
        return redirect('/pdf/view')

@app.route('/pdf/view')
def view_pdf():
    '''
    List all uploaded PDF files and provide links to download
    '''
    files = os.listdir('./uploads')
    pdf_files = [file for file in files if file.endswith('.pdf')]
    return '\n'.join([f'<a href="/pdf/download/{file}">{file}</a>' for file in pdf_files])

@app.route('/pdf/download/<filename>')
def download_pdf(filename):
    '''
    Download a PDF file
    '''
    return send_file(os.path.join('./uploads', filename), as_attachment=True)

if __name__ == '__main__':
    app.run(debug=True)
