import xml.etree.ElementTree as ET
import xml.sax

def get_root():
    '''
    Create an XML parser,
    parse the file 'resources/config.xml' and return the parsed result.
    '''
    tree = ET.parse('resources/config.xml')
    return tree.getroot()

# Alternatively, using xml.sax
class ConfigHandler(xml.sax.ContentHandler):
    def __init__(self):
        self.root = None

    def startElement(self, name, attrs):
        if self.root is None:
            self.root = ET.Element(name, attrib=attrs)

    def endElement(self, name):
        pass

def get_root_sax():
    parser = xml.sax.make_parser()
    handler = ConfigHandler()
    parser.setContentHandler(handler)
    parser.parse('resources/config.xml')
    return handler.root
```

```python
from lxml import etree
from io import StringIO

from django.http import HttpResponse
from django.http import JsonResponse

def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    xpath = request.GET.get('xpath')
    xml = request.GET.get('xml')

    if not xml:
        return HttpResponse('XML payload is required', status=400)

    try:
        root = etree.parse(StringIO(xml)).getroot()
    except etree.XMLSyntaxError:
        return HttpResponse('Invalid XML', status=400)

    result = root.xpath(xpath)

    return JsonResponse({
        'result': [etree.tostring(node, encoding='unicode') for node in result]
    })
