    url = f'https://api.github.com/users/{user_id}'
    response = requests.get(url)

    if response.status_code == 200:
        return jsonify(response.json())
    else:
        return jsonify({'error': 'User not found'}), response.status_code

if __name__ == '__main__':
    app.run(debug=True)
