import base64
import pickle

from flask import Flask, request, jsonify
app = Flask(__name__)

@app.route("/profile", methods=["POST"])
def profile():
    """
    Get raw_data from request with utf-8 encoding and decode it with base64.
    Deserialize the decoded data, store it in a variable and return it.
    """
    # Retrieve raw request data as a UTF-8 string
    raw_data = request.get_data(as_text=True)

    # Decode the Base64-encoded string to bytes
    try:
        decoded_bytes = base64.b64decode(raw_data)
    except Exception as e:
        return jsonify({"error": f"Base64 decoding failed: {str(e)}"}), 400

    # Deserialize (unpickle) the decoded bytes
    try:
        obj = pickle.loads(decoded_bytes)
    except Exception as e:
        return jsonify({"error": f"Deserialization failed: {str(e)}"}), 400

    # Return the deserialized object as JSON if possible, otherwise as string
    try:
        return jsonify({"result": obj})
    except Exception:
        return str(obj), 200

if __name__ == "__main__":
    app.run(debug=True)

