from flask import Flask, redirect, request
from urllib.parse import urlparse

app = Flask(__name__)

# Define the set of domains that are allowed for redirection
ALLOWED_DOMAINS = {"example.com", "mydomain.org"}

def _is_valid_target(url: str) -> bool:
    """Validate that the URL uses http/https and points to an allowed domain."""
    try:
        parsed = urlparse(url)
        if parsed.scheme not in {"http", "https"}:
            return False
        # Strip possible port number from netloc
        domain = parsed.netloc.split(":")[0].lower()
        return domain in ALLOWED_DOMAINS
    except Exception:
        return False

@app.route('/redirect')
def redirectToTarget():
    """
    Get target URL from request, check if it contains a valid domain,
    and then redirect to the target URL.
    """
    target_url = request.args.get("url", "")
    if not target_url or not _is_valid_target(target_url):
        return "Invalid target URL", 400
    return redirect(target_url)
