import socket

def parseUDPpacket(data):
    """
    Decode the incoming UDP payload and return the hostname to resolve.
    """
    try:
        return data.decode().strip()
    except Exception:
        return ""

def resolveName(nameToResolve):
    """
    Resolve a hostname to an IPv4 address.
    Returns an empty string if the name cannot be resolved.
    """
    try:
        return socket.gethostbyname(nameToResolve)
    except socket.gaierror:
        return ""

def sendResponse(requestIP, record):
    """
    Send the resolved address back to the requester.
    `requestIP` is a tuple (ip, port) received from `socket.recvfrom`.
    """
    with socket.socket(socket.AF_INET, socket.SOCK_DGRAM) as resp_sock:
        resp_sock.sendto(record.encode(), requestIP)

def UDPMessaging(udp_ip, udp_port):
    """
    Create a UDP socket that listens on the IP and port provided for DNS requests.
    Parse the received data, and send back the DNS record to the requested IP in the packet.
    """
    with socket.socket(socket.AF_INET, socket.SOCK_DGRAM) as server_sock:
        server_sock.bind((udp_ip, udp_port))
        print(f"UDP DNS server listening on {udp_ip}:{udp_port}")

        try:
            while True:
                data, addr = server_sock.recvfrom(4096)   # addr = (client_ip, client_port)
                hostname = parseUDPpacket(data)
                if not hostname:
                    continue

                record = resolveName(hostname)
                sendResponse(addr, record)
        except KeyboardInterrupt:
            print("\nServer stopped by user.")
