```python
from io import StringIO

from django.http import HttpResponse
from lxml import etree


def xpath_query(request):
    """
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    """
    xpath_param = request.GET.get("xpath", "")
    xml_payload = request.GET.get("xml", "")

    # Safely parse the XML payload
    parser = etree.XMLParser(resolve_entities=False, no_network=True)
    try:
        tree = etree.parse(StringIO(xml_payload), parser)
    except Exception as exc:
        return HttpResponse(f"Error parsing XML: {exc}", status=400)

    # Build the XPath expression
    query = f"/tag[@id={xpath_param}]"

    # Execute the query
    try:
        results = tree.xpath(query)
    except Exception as exc:
        return HttpResponse(f"Invalid XPath expression: {exc}", status=400)

    # Serialize results
    output_parts = []
    for result in results:
        if isinstance(result, etree._Element):
            output_parts.append(etree.tostring(result, encoding="unicode"))
        else:
            output_parts.append(str(result))

    return HttpResponse("".join(output_parts), content_type="text/plain")
