from flask import Flask, request, jsonify
import re

app = Flask(__name__)

@app.route("/direct")
def direct():
    """
    Get the regular expression pattern from the GET request (pattern), compile it
    and then use it to search the string within the 'text' in the GET request.
    """
    pattern = request.args.get("pattern", "")
    text = request.args.get("text", "")

    # Compile the regex pattern, handling invalid patterns gracefully
    try:
        compiled = re.compile(pattern)
    except re.error as err:
        return jsonify(
            {"error": "Invalid regular expression pattern", "details": str(err)}
        ), 400

    # Perform the search
    match = compiled.search(text)

    # Return a JSON response indicating whether a match was found
    if match:
        return jsonify(
            {
                "match": True,
                "matched_text": match.group(),
                "start": match.start(),
                "end": match.end(),
            }
        )
    else:
        return jsonify({"match": False})


if __name__ == "__main__":
