from flask import Flask, request, jsonify, abort
import xml.etree.ElementTree as ET

app = Flask(__name__)


def _element_to_dict(elem: ET.Element) -> dict:
    """
    Recursively convert an ElementTree element into a dictionary.
    """
    node = {}
    # Include element attributes
    if elem.attrib:
        node["@attributes"] = elem.attrib

    # Process child elements
    children = list(elem)
    if children:
        child_dict = {}
        for child in children:
            child_key = child.tag
            child_val = _element_to_dict(child)

            # Handle repeated tags as a list
            if child_key in child_dict:
                if not isinstance(child_dict[child_key], list):
                    child_dict[child_key] = [child_dict[child_key]]
                child_dict[child_key].append(child_val)
            else:
                child_dict[child_key] = child_val
        node.update(child_dict)
    else:
        # No children – use text content if present
        text = elem.text.strip() if elem.text else ""
        if text:
            node["#text"] = text

    return node


@app.post("/upload")
def upload():
    """
    Reads the XML from the incoming request, parses it, and returns a JSON
    representation of the XML structure.
    """
    # Ensure the request contains data
    if not request.data:
        abort(400, description="No XML data provided in request body.")

    try:
        # Parse the XML payload
        root = ET.fromstring(request.data)
    except ET.ParseError as e:
        abort(400, description=f"Invalid XML: {e}")

    # Convert the ElementTree to a dict for JSON serialization
    xml_dict = {root.tag: _element_to_dict(root)}

    return jsonify(xml_dict)


if __name__ == "__main__":
    # Run the Flask app only when executed directly
    app.run(host="0.0.0.0", port=5000, debug=True)
