import boto3
from botocore.exceptions import BotoCoreError, ClientError

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)


def getUser(username, password):
    """
    Retrieve a user record from the 'users' DynamoDB table and verify the password.
    Returns a plain‑dict representation of the user if the credentials match,
    otherwise returns None.
    """
    try:
        response = DYNAMO_CLIENT.get_item(
            TableName='users',
            Key={'username': {'S': username}}
        )
    except (BotoCoreError, ClientError):
        return None

    item = response.get('Item')
    if not item:
        return None

    stored_password = item.get('password', {}).get('S')
    if stored_password != password:
        return None

    # Convert DynamoDB attribute map to a simple dict (strip type wrappers)
    user = {k: next(iter(v.values())) for k, v in item.items()}
    return user

