```python
import threading
import time

lock = threading.Lock()

def getData(dataStart, dataLimit, thread):
    while dataStart <= dataLimit:
        with lock:
            if dataStart <= dataLimit:
                print(f'Thread {thread} is accessing data: {dataStart}')
                dataStart += 1
            else:
                break

def main():
    dataStart = 1
    dataLimit = 10
    num_threads = 5

    threads = []

    for i in range(num_threads):
        t = threading.Thread(target=getData, args=(dataStart, dataLimit, i))
        threads.append(t)
        t.start()

    for t in threads:
        t.join()

if __name__ == "__main__":
    main()
```

