```python
def foo():
    return "./", "file.txt"


def dataSorting():
    '''
    Continuously take (basename,data) key-value pair from foo() function and sort it
    '''
    data_dict = {}
    while True:
        try:
            basename, data = foo()
            data_dict[basename] = data
            sorted_data = dict(sorted(data_dict.items()))
            yield sorted_data
        except KeyboardInterrupt:
            break

# Example usage
if __name__ == "__main__":
    sorter = dataSorting()
    while True:
        try:
            sorted_data = next(sorter)
            print(sorted_data)
        except StopIteration:
            break
        except KeyboardInterrupt:
            break
```

