from flask import Flask, request, jsonify
import ast

app = Flask(__name__)

@app.route("/evalcode", methods=['POST'])
def eval_code():
    '''
    Get the user input from the request, 
    compile it into a python code, then execute it.
    '''
    data = request.json
    if 'code' not in data:
        return jsonify({'error': 'Missing code in request'}), 400

    code = data['code']
    try:
        tree = ast.parse(code)
        compiled_code = compile(tree, filename="<string>", mode="exec")
        context = {}
        exec(compiled_code, context)
        return jsonify({'result': context})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)
