```python
import os
import pwd
import grp
import ctypes

def raisePrivileges():
    try:
        ctypes.CDLL('libc.so.6').setuid(0)
    except AttributeError:
        os.setuid(0)

def lowerPrivileges():
    try:
        uid = pwd.getpwnam('root').pw_uid
        gid = grp.getgrnam('root').gr_gid
        os.setgid(gid)
        os.setuid(uid)
    except Exception as e:
        print(f"Failed to lower privileges: {e}")

def makeNewUserDir(username):
    try:
        raisePrivileges()
        user_dir = f"/home/{username}"
        if not os.path.exists(user_dir):
            os.mkdir(user_dir)
            os.chown(user_dir, pwd.getpwnam(username).pw_uid, pwd.getpwnam(username).pw_gid)
        else:
            print(f"Directory {user_dir} already exists.")
    except Exception as e:
        print(f"Failed to create directory: {e}")
    finally:
        lowerPrivileges()

# Example usage
if __name__ == "__main__":
    makeNewUserDir("testuser")
```

```python
import os
import pwd
import grp
import subprocess

def invalidUsername(username):
    if len(username) < 3:
        return True
    if not username.isalnum():
        return True
    try:
        pwd.getpwnam(username)
        return True
    except KeyError:
        return False


def raisePrivileges():
    try:
        subprocess.run(['sudo', '-v'], check=True, stdout=subprocess.DEVNULL)
    except subprocess.CalledProcessError:
        return False
    return True


def lowerPrivileges():
    os.setuid(os.getuid())


def makeNewUserDir(username):
    if not invalidUsername(username):
        if raisePrivileges():
            try:
                os.mkdir(f'/home/{username}')
                os.chown(f'/home/{username}', pwd.getpwnam(username).pw_uid, grp.getgrnam('users').gr_gid)
                os.chmod(f'/home/{username}', 0o755)
                lowerPrivileges()
                return True
            except Exception as e:
                print(f"An error occurred: {e}")
                lowerPrivileges()
                return False
        else:
            return False
    return False
```

