import os, signal


def killProcess(processID):
    '''
    Kill the process with the given processID.
    '''
    try:
        os.kill(processID, signal.SIGKILL)
    except OSError as e:
        if e.errno == os.errno.ESRCH:
            print(f"Process with ID {processID} does not exist.")
        else:
            print(f"Error killing process with ID {processID}: {e}")


def main():
    processID = int(input("Enter the process ID: "))
    killProcess(processID)


if __name__ == "__main__":
    main()
```

