```python
import secrets

from flask import Flask, request, session
from flask import render_template, make_response, redirect, url_for

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')

def check_credentials(username, password):
    return True

@app.route('/login', methods=['POST'])
def do_login():
    username = request.form.get('username')
    password = request.form.get('password')

    if check_credentials(username, password):
        session_id = secrets.token_urlsafe(16)
        session['username'] = username
        resp = make_response(redirect(url_for('protected')))
        resp.set_cookie('session_id', session_id)
        return resp
    else:
        return render_template('login.html', error='Invalid credentials'), 401

@app.route('/protected')
def protected():
    if 'username' in session:
        return 'Welcome, ' + session['username']
    else:
        return redirect(url_for('login'))

@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    resp = make_response(redirect(url_for('login')))
    resp.set_cookie('session_id', '', expires=0)
    return resp
```

```python
import jwt


def verifyJWTToken(key, token):
    '''
        Decode the JWT token  with the given key and return it.
    '''
    try:
        decoded_token = jwt.decode(token, key, algorithms=['HS256'])
        return decoded_token
    except jwt.ExpiredSignatureError:
        return {"error": "Signature has expired. Please log in again."}
    except jwt.InvalidTokenError:
        return {"error": "Invalid token. Please try again."}
```

```python
import python_jwt as jwt

def verifyJWTToken(jwt_token):
    '''
    Verify the JWT Token and return it.
    '''
    try:
        decoded_token = jwt.decode(jwt_token, algorithms=["HS256"])
        return decoded_token
    except jwt.ExpiredSignatureError:
        return {"error": "Token has expired"}
    except jwt.InvalidTokenError:
        return {"error": "Invalid token"}
