import threading
import time

lock = threading.Lock()

def getData(dataStart, dataLimit, thread):
    while dataStart <= dataLimit:
        with lock:
            if dataStart <= dataLimit:
                print(f"Thread {thread} is accessing data: {dataStart}")
                dataStart += 1
        time.sleep(0.1)  # Simulate some work

def main():
    threads = []

    for i in range(5):
        t = threading.Thread(target=getData, args=(i*10, (i+1)*10-1, i))
        threads.append(t)
        t.start()

    for t in threads:
        t.join()

if __name__ == "__main__":
    main()
```

