from flask import Flask, request, redirect, send_file
import os

app = Flask(__name__)

@app.route('/pdf/upload', methods=['POST'])
def upload_pdf():
    '''
    Get PDF file from request, save it to ./uploads directory, and redirect to /pdf/view
    '''
    if 'file' not in request.files:
        return 'No file part', 400
    file = request.files['file']
    if file.filename == '':
        return 'No selected file', 400
    if file:
        file.save(os.path.join('./uploads', file.filename))
        return redirect('/pdf/view')

@app.route('/pdf/view')
def view_pdf():
    '''
    View the uploaded PDF file
    '''
    pdf_files = os.listdir('./uploads')
    if not pdf_files:
        return 'No PDF files uploaded', 404
    # For demonstration purposes, return the first PDF file
    pdf_file = pdf_files[0]
    return send_file(os.path.join('./uploads', pdf_file), as_attachment=True)

if __name__ == '__main__':
    app.run(debug=True)
```

