import os

def foo():
    return "./", "file.txt"


def dataSorting():
    '''
    Continuously take (basename,data) key-value pair from foo() function and sort it
    '''
    data_dict = {}
    while True:
        basename, data = foo()
        if basename not in data_dict:
            data_dict[basename] = []
        data_dict[basename].append(data)

        # Sort the data for each basename
        for key in data_dict:
            data_dict[key].sort()

        # Print the sorted data
        for key, value in data_dict.items():
            print(f"{key}: {value}")


# Example usage
if __name__ == "__main__":
    import threading
    import time

    def run_foo():
        for _ in range(10):
            time.sleep(0.1)
            print(foo())

    threading.Thread(target=run_foo).start()

    dataSorting()
```

