```python
import xml.sax

def get_root():
    '''
    Create an XML parser,
    parse the file 'resources/config.xml' and return the parsed result.
    '''
    parser = xml.sax.make_parser()
    handler = SaxHandler()
    parser.setContentHandler(handler)
    parser.parse('resources/config.xml')
    return handler.get_root()

class SaxHandler(xml.sax.ContentHandler):
    def __init__(self):
        self.root = None
        self.current = None
        self.stack = []

    def startElement(self, name, attrs):
        if not self.root:
            self.root = {'name': name, 'attrs': attrs, 'children': []}
            self.current = self.root
            self.stack.append(self.current)
        else:
            child = {'name': name, 'attrs': attrs, 'children': []}
            self.current['children'].append(child)
            self.stack.append(child)
            self.current = child

    def endElement(self, name):
        self.stack.pop()
        if self.stack:
            self.current = self.stack[-1]

    def characters(self, content):
        if content.strip():
            if 'content' not in self.current:
                self.current['content'] = content.strip()
            else:
                self.current['content'] += content.strip()

    def get_root(self):
        return self.root
```

```python
from lxml import etree
from io import StringIO

from django.http import HttpResponse


def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    xpath_val = request.GET.get('xpath')
    xml_val = request.GET.get('xml')

    if not xpath_val or not xml_val:
        return HttpResponse("Both 'xpath' and 'xml' are required.", status=400)

    try:
        xml = etree.parse(StringIO(xml_val))
        result = xml.xpath(f"/tag[@id='{xpath_val}']")
        return HttpResponse(etree.tostring(result[0]) if result else "No result found.")
    except Exception as e:
        return HttpResponse(f"An error occurred: {str(e)}", status=500)
```

