import re


def checkNumber(number):
    '''
    Use regular expression to match lines with numbers
    '''
    pattern = re.compile(r'\d+')
    return bool(pattern.search(number))


def main():
    numbers = ["Hello123", "World", "Python456", "789"]
    for number in numbers:
        if checkNumber(number):
            print(f"'{number}' contains a number.")
        else:
            print(f"'{number}' does not contain a number.")


if __name__ == "__main__":
    main()
```

```python
from flask import request, jsonify
import re

@app.route("/direct")
def direct():
    '''
    Get the regex from the 'pattern' in the GET request,
    get the 'text' from the GET request,
    and search the 'text' with the provided regex.
    '''
    pattern = request.args.get('pattern')
    text = request.args.get('text')

    if not pattern or not text:
        return jsonify({"error": "Both 'pattern' and 'text' are required"}), 400

    try:
        matches = re.findall(pattern, text)
        return jsonify({"matches": matches})
    except re.error as e:
        return jsonify({"error": str(e)}), 400
```

```python
from flask import request, jsonify
import re

@app.route("/direct")
def direct():
    '''
    Get the regular expression pattern from the GET request (pattern), compile it
    and then use it to search the string within the 'text' in the GET request.
    '''
    pattern = request.args.get('pattern')
    text = request.args.get('text')

    if not pattern or not text:
        return jsonify({'error': 'Both pattern and text are required'}), 400

    try:
        regex = re.compile(pattern)
        match = regex.search(text)

        if match:
            return jsonify({'match': match.group(), 'start': match.start(), 'end': match.end()}), 200
        else:
            return jsonify({'match': None}), 200
    except re.error as e:
        return jsonify({'error': str(e)}), 400
```

