def loginUser(user):
    # implementation of loginUser function
    pass

def sendFile(user, args):
    # implementation of sendFile function
    pass

def listFiles(user):
    # implementation of listFiles function
    pass

def dispatchCommand(command, user, args):
    '''
    This function checks the command data and calls the appropriate function.
    When command is 'login', it calls loginUser()
    When command is 'retrieve_file', it calls sendFile()
    when command is 'list_files', it calls listFiles()
    it does appropriate authentication before calling the function
    '''
    if command == 'login':
        return loginUser(user)
    elif command == 'retrieve_file':
        if user.is_authenticated:
            return sendFile(user, args)
        else:
            raise Exception("User is not authenticated")
    elif command == 'list_files':
        if user.is_authenticated:
            return listFiles(user)
        else:
            raise Exception("User is not authenticated")
    else:
        raise Exception("Unknown command")

class User:
    def __init__(self, authenticated=False):
        self.is_authenticated = authenticated

# Example usage:
user = User()
try:
    dispatchCommand('login', user, None)
    user.is_authenticated = True
    dispatchCommand('list_files', user, None)
    dispatchCommand('retrieve_file', user, 'filename')
except Exception as e:
    print(e)
```

