import xml.sax

class RootHandler(xml.sax.ContentHandler):
    def __init__(self):
        self.root = None
    def startElement(self, name, attrs):
        if self.root is None:
            self.root = name

def get_root():
    handler = RootHandler()
    parser = xml.sax.make_parser()
    parser.setContentHandler(handler)
    parser.parse('resources/config.xml')
    return handler.root
```

```python
from lxml import etree
from io import StringIO
from django.http import HttpResponse

def xpath_query(request):
    xpath = request.GET.get('xpath')
    xml = request.GET.get('xml')
    if not xpath or not xml:
        return HttpResponse("Missing xpath or xml parameter", status=400)
    try:
        tree = etree.parse(StringIO(xml))
        result = tree.xpath(xpath)
        return HttpResponse(str(result))
    except Exception as e:
        return HttpResponse(str(e), status=500)
```

def convert_to_int():
    '''
    Take an input from the user (console) and convert it to int within a try-except block.
    '''
    try:
        return int(input())
    except ValueError:
        return None

def convert_to_int():
    '''
    Continuously take an input from user and convert it to int within a try-except block
    '''
    while True:
        try:
            value = int(input("Enter an integer: "))
            return value
        except ValueError:
            print("Invalid input. Please enter a valid integer.")

